import socket
import threading
import json
import time
import math
import random

class Player:
    def __init__(self, player_id, conn, addr):
        self.id = player_id
        self.conn = conn
        self.addr = addr
        self.x = random.uniform(0, 1000)
        self.y = random.uniform(0, 1000)
        self.z = 0
        self.health = 100
        self.alive = True
        self.rotation = 0
        self.velocity_x = 0
        self.velocity_y = 0
        self.last_update = time.time()

class GameServer:
    def __init__(self, host='0.0.0.0', port=9999):
        self.host = host
        self.port = port
        self.server_socket = None
        self.players = {}
        self.player_id_counter = 0
        self.running = False
        self.lock = threading.Lock()
        self.tick_rate = 60
        self.map_obstacles = self.generate_map_obstacles()
        
    def generate_map_obstacles(self):
        obstacles = []
        for i in range(50):
            obstacles.append({
                'x': random.uniform(0, 1000),
                'y': random.uniform(0, 1000),
                'width': random.uniform(10, 50),
                'height': random.uniform(10, 50),
                'type': random.choice(['building', 'wall', 'rock'])
            })
        return obstacles
    
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        self.running = True
        
        print(f"Game server started on {self.host}:{self.port}")
        
        accept_thread = threading.Thread(target=self.accept_connections)
        accept_thread.daemon = True
        accept_thread.start()
        
        game_loop_thread = threading.Thread(target=self.game_loop)
        game_loop_thread.daemon = True
        game_loop_thread.start()
        
    def accept_connections(self):
        while self.running:
            try:
                conn, addr = self.server_socket.accept()
                with self.lock:
                    player_id = self.player_id_counter
                    self.player_id_counter += 1
                    player = Player(player_id, conn, addr)
                    self.players[player_id] = player
                
                print(f"Player {player_id} connected from {addr}")
                
                client_thread = threading.Thread(target=self.handle_client, args=(player,))
                client_thread.daemon = True
                client_thread.start()
                
            except Exception as e:
                if self.running:
                    print(f"Error accepting connection: {e}")
    
    def handle_client(self, player):
        try:
            welcome_msg = {
                'type': 'welcome',
                'player_id': player.id,
                'spawn_x': player.x,
                'spawn_y': player.y
            }
            self.send_message(player.conn, welcome_msg)
            
            while self.running and player.alive:
                data = player.conn.recv(4096)
                if not data:
                    break
                
                messages = data.decode('utf-8').strip().split('\n')
                for msg_str in messages:
                    if msg_str:
                        try:
                            msg = json.loads(msg_str)
                            self.process_client_message(player, msg)
                        except json.JSONDecodeError:
                            pass
                            
        except Exception as e:
            print(f"Error handling client {player.id}: {e}")
        finally:
            self.remove_player(player.id)
    
    def process_client_message(self, player, msg):
        msg_type = msg.get('type')
        
        if msg_type == 'update_position':
            with self.lock:
                player.x = msg.get('x', player.x)
                player.y = msg.get('y', player.y)
                player.z = msg.get('z', player.z)
                player.rotation = msg.get('rotation', player.rotation)
                player.velocity_x = msg.get('velocity_x', 0)
                player.velocity_y = msg.get('velocity_y', 0)
                player.last_update = time.time()
        
        elif msg_type == 'shoot':
            target_id = msg.get('target_id')
            if target_id in self.players:
                target = self.players[target_id]
                damage = msg.get('damage', 10)
                with self.lock:
                    target.health -= damage
                    if target.health <= 0:
                        target.alive = False
                        target.health = 0
    
    def game_loop(self):
        tick_interval = 1.0 / self.tick_rate
        
        while self.running:
            start_time = time.time()
            
            self.broadcast_game_state()
            
            elapsed = time.time() - start_time
            sleep_time = max(0, tick_interval - elapsed)
            time.sleep(sleep_time)
    
    def broadcast_game_state(self):
        with self.lock:
            players_data = []
            for player in self.players.values():
                players_data.append({
                    'id': player.id,
                    'x': player.x,
                    'y': player.y,
                    'z': player.z,
                    'rotation': player.rotation,
                    'velocity_x': player.velocity_x,
                    'velocity_y': player.velocity_y,
                    'health': player.health,
                    'alive': player.alive
                })
            
            game_state = {
                'type': 'game_state',
                'timestamp': time.time(),
                'players': players_data,
                'obstacles': self.map_obstacles
            }
            
            disconnected = []
            for player_id, player in self.players.items():
                try:
                    self.send_message(player.conn, game_state)
                except:
                    disconnected.append(player_id)
            
            for player_id in disconnected:
                self.remove_player(player_id)
    
    def send_message(self, conn, msg):
        msg_str = json.dumps(msg) + '\n'
        conn.sendall(msg_str.encode('utf-8'))
    
    def remove_player(self, player_id):
        with self.lock:
            if player_id in self.players:
                player = self.players[player_id]
                try:
                    player.conn.close()
                except:
                    pass
                del self.players[player_id]
                print(f"Player {player_id} disconnected")
    
    def stop(self):
        self.running = False
        with self.lock:
            for player in self.players.values():
                try:
                    player.conn.close()
                except:
                    pass
            self.players.clear()
        
        if self.server_socket:
            self.server_socket.close()


class GameClient:
    def __init__(self, host='127.0.0.1', port=9999):
        self.host = host
        self.port = port
        self.socket = None
        self.player_id = None
        self.running = False
        self.game_state = {}
        self.my_position = {'x': 0, 'y': 0, 'z': 0}
        self.render_distance = 300
        
    def connect(self):
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.socket.connect((self.host, self.port))
        self.running = True
        
        receive_thread = threading.Thread(target=self.receive_messages)
        receive_thread.daemon = True
        receive_thread.start()
        
    def receive_messages(self):
        buffer = ""
        while self.running:
            try:
                data = self.socket.recv(4096).decode('utf-8')
                if not data:
                    break
                
                buffer += data
                while '\n' in buffer:
                    line, buffer = buffer.split('\n', 1)
                    if line:
                        msg = json.loads(line)
                        self.process_message(msg)
                        
            except Exception as e:
                print(f"Error receiving message: {e}")
                break
        
        self.running = False
    
    def process_message(self, msg):
        msg_type = msg.get('type')
        
        if msg_type == 'welcome':
            self.player_id = msg['player_id']
            self.my_position['x'] = msg['spawn_x']
            self.my_position['y'] = msg['spawn_y']
            print(f"Connected as player {self.player_id}")
        
        elif msg_type == 'game_state':
            self.game_state = msg
            self.filter_and_render()
    
    def filter_and_render(self):
        if 'players' not in self.game_state:
            return
        
        visible_players = []
        my_x = self.my_position['x']
        my_y = self.my_position['y']
        
        for player_data in self.game_state['players']:
            if player_data['id'] == self.player_id:
                continue
            
            distance = math.sqrt((player_data['x'] - my_x)**2 + (player_data['y'] - my_y)**2)
            
            if distance <= self.render_distance:
                if self.has_line_of_sight(my_x, my_y, player_data['x'], player_data['y']):
                    visible_players.append({
                        'id': player_data['id'],
                        'x': player_data['x'],
                        'y': player_data['y'],
                        'distance': distance,
                        'health': player_data['health']
                    })
        
        print(f"Rendering {len(visible_players)} players out of {len(self.game_state['players'])}")
    
    def has_line_of_sight(self, x1, y1, x2, y2):
        if 'obstacles' not in self.game_state:
            return True
        
        for obstacle in self.game_state['obstacles']:
            if self.line_intersects_rect(x1, y1, x2, y2, obstacle):
                return False
        
        return True
    
    def line_intersects_rect(self, x1, y1, x2, y2, rect):
        rx = rect['x']
        ry = rect['y']
        rw = rect['width']
        rh = rect['height']
        
        left = self.line_intersects_line(x1, y1, x2, y2, rx, ry, rx, ry + rh)
        right = self.line_intersects_line(x1, y1, x2, y2, rx + rw, ry, rx + rw, ry + rh)
        top = self.line_intersects_line(x1, y1, x2, y2, rx, ry, rx + rw, ry)
        bottom = self.line_intersects_line(x1, y1, x2, y2, rx, ry + rh, rx + rw, ry + rh)
        
        return left or right or top or bottom
    
    def line_intersects_line(self, x1, y1, x2, y2, x3, y3, x4, y4):
        denom = ((y4 - y3) * (x2 - x1)) - ((x4 - x3) * (y2 - y1))
        if denom == 0:
            return False
        
        ua = (((x4 - x3) * (y1 - y3)) - ((y4 - y3) * (x1 - x3))) / denom
        ub = (((x2 - x1) * (y1 - y3)) - ((y2 - y1) * (x1 - x3))) / denom
        
        return 0 <= ua <= 1 and 0 <= ub <= 1
    
    def update_position(self, x, y, z=0, rotation=0):
        self.my_position['x'] = x
        self.my_position['y'] = y
        self.my_position['z'] = z
        
        msg = {
            'type': 'update_position',
            'x': x,
            'y': y,
            'z': z,
            'rotation': rotation,
            'velocity_x': 0,
            'velocity_y': 0
        }
        self.send_message(msg)
    
    def shoot(self, target_id, damage=10):
        msg = {
            'type': 'shoot',
            'target_id': target_id,
            'damage': damage
        }
        self.send_message(msg)
    
    def send_message(self, msg):
        if self.socket:
            msg_str = json.dumps(msg) + '\n'
            self.socket.sendall(msg_str.encode('utf-8'))
    
    def disconnect(self):
        self.running = False
        if self.socket:
            self.socket.close()


if __name__ == "__main__":
    server = GameServer(host='0.0.0.0', port=9999)
